/**
 * @param {HttpInput} input
 * @param {SDK} sdk
 * @returns {MaybePromise<Data | undefined>}
 */
export async function run({ request, response }, sdk) {
  if ((request && response) && (request.getMethod() === "GET")) {
    if (response.getHeader("content-type")){
      let contentType = response.getHeader("content-type").toString();
      if (
        contentType &&
        !contentType.includes("javascript") &&
        !contentType.includes("html")
      ) {
        return;
      }
      let body = response.getBody().toText();
      if (!body) return;

      const patterns = [
        /window\.addEventListener\s*\(\s*['"]message['"]/gi,
        /addEventListener\s*\(\s*['"]message['"]/gi,
        /window\.onmessage\s*=/gi,
        /\.onmessage\s*=/gi,
        /self\.addEventListener\s*\(\s*['"]message['"]/gi
      ];

      let matches = [];

      for (let pattern of patterns) {
        let found = body.match(pattern);
        if (found) {
          matches.push(...found);
        }
      }

      if (matches.length > 0) {
        let url = request.getUrl();

        sdk.console.log(`FOUND postMessage listener on ${url}`);

        await sdk.findings.create({
          title: "postMessage Listener Detected",
          description: `PostMessage Listener Detected:\n\n ${matches.toString()}`,
          request: request,
          reporter: "caido-workflow",
          dedupeKey: `postmessage-${url}`
        });
      }
    }
  }
}
